        let v = Int(edge[1])
        adjacencyList[u].append(v)
        adjacencyList[v].append(u)
    }

    var maxLength = 1
    let labels = Array(label)

    for start in 0..<nodeCount {
        var visited = [Bool](repeating: false, count: nodeCount)
        var path: [Character] = []
        dfs(start, &visited, &path, adjacencyList, labels, &maxLength)
    }

    return Int64(maxLength)
}

private func dfs(_ node: Int, _ visited: inout [Bool], _ path: inout [Character], _ adjacencyList: [[Int]], _ labels: [Character], _ maxLength: inout Int) {
    visited[node] = true
    path.append(labels[node])

